//! `GET /demo/personas`: JSON list of Approved-only personas from the
//! D1 catalog, populated into the welcome page's chat picker on first
//! open. Stripped down to the four fields the picker needs (slug,
//! label, description, greeting); the demo-augmented prompt rides
//! along so the "View system prompt" panel matches what `/demo/chat`
//! actually sends. Each row carries a sample business (name, type,
//! city, hours, goal) generated by the LLM under the operator's
//! configurable generation prompt, so the UI can render a "you're
//! chatting as a customer of …" card under the picker.

use serde::{Deserialize, Serialize};
use worker::*;

use crate::storage;

const CACHE_TTL_SECONDS: u64 = 300;

#[derive(Serialize, Deserialize, Clone, Default)]
pub(crate) struct DemoBusiness {
    #[serde(default)]
    pub name: String,
    #[serde(default)]
    pub business_type: String,
    #[serde(default)]
    pub city: String,
    #[serde(default)]
    pub hours: String,
    #[serde(default)]
    pub goal: String,
    #[serde(default)]
    pub goal_url: String,
}

#[derive(Serialize, Deserialize, Clone)]
struct DemoPersonaPayload {
    slug: String,
    label: String,
    description: String,
    greeting: String,
    /// The exact middle (frame + persona prompt) sent to the model on
    /// `/demo/chat`. Rendered in the "View system prompt" panel.
    prompt: String,
    business: DemoBusiness,
}

#[derive(Serialize, Deserialize, Clone)]
struct DemoPersonasResponse {
    personas: Vec<DemoPersonaPayload>,
}

pub async fn handle_demo_personas(_req: Request, env: Env) -> Result<Response> {
    let kv = env.kv("KV")?;
    let db = env.d1("DB")?;

    // Demo gate. When the operator has flipped the toggle off, return
    // an empty list so the picker shows nothing and the welcome page's
    // chat factory has nothing to render.
    let demo_cfg = storage::get_demo_config(&kv).await.unwrap_or_default();
    if !demo_cfg.enabled {
        return json_response(DemoPersonasResponse {
            personas: Vec::new(),
        });
    }

    // 1. Check KV cache
    if let Ok(Some(cached)) = kv
        .get(storage::DEMO_PERSONAS_CACHE_KEY)
        .json::<DemoPersonasResponse>()
        .await
    {
        return json_response(cached);
    }

    // 2. Fetch approved archetypes
    let archetypes = storage::list_archetypes(&db, true)
        .await
        .unwrap_or_default();

    // 3. Generate fictional business details for each archetype.
    let mut personas = Vec::with_capacity(archetypes.len());

    if !archetypes.is_empty() {
        if let Ok(businesses) =
            generate_demo_businesses(&env, &demo_cfg.persona_generation_prompt, &archetypes).await
        {
            for (i, biz) in businesses.into_iter().enumerate() {
                if let Some(a) = archetypes.get(i) {
                    let builder = crate::types::PersonaBuilder {
                        archetype_slug: a.slug.clone(),
                        biz_name: biz.name.clone(),
                        biz_type: biz.business_type.clone(),
                        city: biz.city.clone(),
                        hours: biz.hours.clone(),
                        goal: biz.goal.clone(),
                        goal_url: biz.goal_url.clone(),
                        ..Default::default()
                    };
                    let persona_middle = crate::personas::generate(&builder, &a.voice_prompt);
                    personas.push(DemoPersonaPayload {
                        slug: a.slug.clone(),
                        label: a.label.clone(),
                        description: a.description.clone(),
                        greeting: a.greeting.clone(),
                        prompt: crate::prompt::compose_demo_middle(&persona_middle),
                        business: biz,
                    });
                }
            }
        }
    }

    let response = DemoPersonasResponse { personas };

    // 4. Cache in KV
    let _ = kv
        .put(
            storage::DEMO_PERSONAS_CACHE_KEY,
            serde_json::to_string(&response)?,
        )?
        .expiration_ttl(CACHE_TTL_SECONDS)
        .execute()
        .await;

    json_response(response)
}

/// Run the operator's generation prompt against the given archetypes
/// and return the parsed sample businesses. Shared by the public demo
/// list and the `/manage/demo/preview` endpoint so the operator sees
/// exactly what the demo will render after a save.
pub(crate) async fn generate_demo_businesses(
    env: &Env,
    system_prompt: &str,
    archetypes: &[crate::types::Archetype],
) -> std::result::Result<Vec<DemoBusiness>, String> {
    let user_prompt = archetypes
        .iter()
        .map(|a| format!("- {} ({})", a.label, a.description))
        .collect::<Vec<_>>()
        .join("\n");

    let reply = crate::ai::generate_chat_reply(
        env,
        system_prompt,
        &vec![("user".to_string(), user_prompt)],
    )
    .await
    .map_err(|e| format!("AI call failed: {e:?}"))?;

    // Strip an optional ```json fence the model sometimes adds.
    let clean = reply
        .trim()
        .trim_start_matches("```json")
        .trim_start_matches("```")
        .trim_end_matches("```")
        .trim();

    serde_json::from_str::<Vec<DemoBusiness>>(clean)
        .map_err(|e| format!("Could not parse JSON array: {e}. Raw reply: {reply}"))
}

fn json_response(data: DemoPersonasResponse) -> Result<Response> {
    let body = serde_json::to_string(&data)?;
    let mut headers = Headers::new();
    headers.set("Content-Type", "application/json")?;
    headers.set("Cache-Control", "no-store")?;
    Ok(Response::ok(body)?.with_headers(headers))
}
